/**
 * Merge multiple rspack configs into one
 * from @rsbuild/core (see https://github.com/web-infra-dev/rsbuild/blob/main/packages/core/src/mergeConfig.ts)
 */
// TODO(env): replace teambit.node/node@2.0.1 with a workspace-owned ESM
// module env (e.g. teambit.rspack/envs/rspack-module-env) whose PackageGenerator
// emits `"type": "module"` on the component package.json. That eliminates the
// suppressions below — @rspack/core@2 is ESM-only and NodeNext rejects type
// imports from ESM packages inside CJS-typed packages, even for `import type`.
// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore TS1479: type-only import from ESM-only @rspack/core under NodeNext (CJS package)
import type { Configuration } from '@rspack/core';
import { isFunction, isPlainObject } from './helpers';

const castArray = <T>(value: T | T[]): T[] => Array.isArray(value) ? value : [value];

const OVERRIDE_PATH = [
  'performance.removeConsole',
  'output.inlineScripts',
  'output.inlineStyles',
  'output.cssModules.auto',
  'output.targets',
  'output.overrideBrowserslist',
  'server.open',
  'server.printUrls',
  'provider',
];

/**
 * When merging configs, some properties prefer `override` over `merge to array`
 */
const isOverridePath = (key: string) => OVERRIDE_PATH.includes(key);

const merge = (x: unknown, y: unknown, path = '') => {
  // force some keys to override
  if (isOverridePath(path)) {
    return y ?? x;
  }

  // ignore undefined property
  if (x === undefined) {
    return y;
  }
  if (y === undefined) {
    return x;
  }

  const pair = [x, y];

  // combine array
  if (pair.some(Array.isArray)) {
    return [...castArray(x), ...castArray(y)];
  }

  // convert function to chained function
  if (pair.some(isFunction)) {
    return pair;
  }

  if (!isPlainObject(x) || !isPlainObject(y)) {
    return y;
  }

  const merged: Record<string, unknown> = {};
  const keys = new Set([...Object.keys(x), ...Object.keys(y)]);

  // eslint-disable-next-line no-restricted-syntax
  for (const key of keys) {
    const childPath = path ? `${path}.${key}` : key;
    merged[key] = merge(x[key], y[key], childPath);
  }

  return merged;
};

export const mergeRspackConfig = (
  ...configs: Configuration[]
): Configuration => {
  if (configs.length === 2) {
    return merge(configs[0], configs[1]) as Configuration;
  }

  if (configs.length < 2) {
    return configs[0];
  }

  return configs.reduce(
    (result, config) => merge(result, config) as Configuration,
    {} as Configuration
  );
};
